@flow(name="Daily ETL", log_prints=True)
def daily_etl(
    start_date: date,
    end_date: date,
    env: Literal["dev", "staging", "prod"] = "dev",
    batch_size: int = 10_000,
    dry_run: bool = False,
    target_table: str = "events",
) -> None:
    records = extract(start_date, end_date, env, batch_size)
    transformed = transform(records, env)
    if not dry_run:
        load(transformed, target_table)
    else:
        print(f"Dry run: would have loaded {len(transformed)} records")

